// BusMap.jsx
import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import "./BusMap.css"; // Make sure the filename matches

export default function BusMap() {
  const [buses, setBuses] = useState([]);
  const [loading, setLoading] = useState(true);

  // Fetch buses from backend
  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const res = await fetch("http://127.0.0.1:8000/buses");
        const data = await res.json();
        setBuses(data || []);
        setLoading(false);
      } catch (err) {
        console.error("Error fetching buses:", err);
        setBuses([]);
        setLoading(false);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 60000); // refresh every 1 min
    return () => clearInterval(interval);
  }, []);

  // Determine color based on bus type
  const getColor = (bus) => {
    if (bus.isAnomaly) return "orange";
    if (bus.isGhost) return "red";
    return "green";
  };

  return (
    <div className="bus-map-container">
      {loading ? (
        <p>Loading buses...</p>
      ) : (
        <MapContainer
          center={[40.7128, -74.006]}
          zoom={12}
          style={{ height: "100vh", width: "100vw" }} // full viewport
        >
          <TileLayer
            url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
            attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
          />
          {buses.map((bus) => (
            <CircleMarker
              key={bus.id}
              center={[bus.lat, bus.lon]}
              radius={8}
              color={getColor(bus)}
              fillOpacity={0.8}
              pathOptions={{ transition: "all 0.5s ease" }} // smooth transition
            >
              <Popup>
                <div>
                  <p><strong>Bus ID:</strong> {bus.id}</p>
                  <p><strong>Status:</strong> {bus.isGhost ? "Ghost" : "Normal"}</p>
                  {bus.isAnomaly && <p style={{ color: "orange" }}>Anomaly detected!</p>}
                </div>
              </Popup>
            </CircleMarker>
          ))}
        </MapContainer>
      )}
    </div>
  );
}
